#include <stdio.h>

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    for (int i = 0; i < T; ++i) {
        if (scanf("%d", &N) != 1) return 0;
        if (N > 0) {
            printf("Positive");
        } else if (N < 0) {
            printf("Negative");
        } else {
            printf("Zero");
        }
        if (i != T - 1) printf("\\n");
    }
    return 0;
}

