import sys

def main():
    data = sys.stdin.read()
    if not data:
        return
    data = data.replace('\\n', '\n')
    tokens = data.split()
    t = int(tokens[0])
    out = []
    idx = 1
    for _ in range(t):
        n = int(tokens[idx])
        idx += 1
        if n > 0:
            out.append('Positive')
        elif n < 0:
            out.append('Negative')
        else:
            out.append('Zero')
    sys.stdout.write('\\n'.join(out))

if __name__ == "__main__":
    main()

